var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"대장님! 저지선이 돌파 당했습니다!","JPN":"隊長！　防衛線が突破されました！","ENG":"Captain! Our defense line has been breached!","TWN":"隊長！警戒線被突破了！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"더는 버티기 힘들겠어.","JPN":"これ以上は耐え切れない……","ENG":"We can't hold out any longer.","TWN":"無法再堅持了。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"......지원은 아직 멀었나?!","JPN":"……支援はまだか！？","ENG":"Where's the help?","TWN":"……支援還沒到嗎？！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PIRATE_FOX_A_NULL","text":{"KOREA":"좋아! 방어선이 무너지고 있어! 더 밀어붙여!","JPN":"よし！　防衛線が崩れ始めている！\\nもっと押し込め！","ENG":"Alright, their defense line has collapsed! Push harder!","TWN":"好！防線馬上就要擊潰了！繼續攻擊！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FOX_A_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIRATE_FOX_A_NULL","text":{"KOREA":"패배자의 물건들은 전부 우리 전리품이다!","JPN":"負け犬どもから何もかも奪い取ってやろうぜ！","ENG":"Everything they have, it's ours now!","TWN":"敗者的東西都是我們的戰利品！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FOX_A_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIRATE_FOX_B_NULL","text":{"KOREA":"......응?","JPN":"……ん？","ENG":"Err?","TWN":"……嗯？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FOX_A_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_AIR_SMALL_START_03"},{"id":"L13_1","type":"dialog","speaker":"PIRATE_FOX_A_NULL","text":{"KOREA":"뭐야, 왜 그래?","JPN":"何だ、どうした？","ENG":"What? What's wrong?","TWN":"怎麼了？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FOX_A_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PIRATE_FOX_B_NULL","text":{"KOREA":"하늘에 저건 뭐지?","JPN":"空のあれは何だ？","ENG":"What's that in the sky above us?","TWN":"天上的那個是什麼東西？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FOX_A_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MECHANIC_COFFIN_START"},{"id":"L15_1","type":"dialog","speaker":"PIRATE_FOX_A_NULL","text":{"KOREA":"수송기인가...... 그런데 아래쪽에 뭔가 엄청난 게 매달려있는데?","JPN":"輸送機か？　……けど、下にものすごいのが\\nぶら下がってるぜ？","ENG":"A transport, it looks like. And it's got something gigantic dangling from it.","TWN":"是運輸機嗎……不過下面好像掛著一個不得了的東西？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FOX_A_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PIRATE_FOX_B_NULL","text":{"KOREA":"이, 이쪽으로 떨어진다! 피해!","JPN":"こ、こっちに落ちてくる！　逃げろ！","ENG":"I-it's falling this way! Watch out!","TWN":"掉，掉下來了！快躲開！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FOX_A_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_08"},{"id":"L21_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"뭐, 뭐야 뭐가 떨어진 거야?","JPN":"な、何だよ。何が落ちたんだ？","ENG":"W-what? What dropped?","TWN":"是什麼東西掉下來了？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"새로운 적인가?","JPN":"新しい敵か？","ENG":"Another enemy?","TWN":"另一批敵人？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하! 걱정하지 말게 호송대 친구들! 타이탄이 여기 왔다네!","JPN":"ハハハ！　心配はいらない、搬送部隊の諸君！\\nタイタンの登場だ！","ENG":"Hah hah! Worry not, my friends! Titan came to your rescue!","TWN":"哈哈！不用擔心，護送隊朋友們！泰坦來也！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"타, 타이탄?","JPN":"タ、タイタン？","ENG":"T-Titan?","TWN":"泰，泰坦？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"저거 혹시 명령 불복종 문제로 동결 처리 당한 그 로봇 아니야?","JPN":"もしかして、命令不服従で除外されていた\\nあのロボットじゃないか？","ENG":"Isn't it the disobedient robot that was frozen away?","TWN":"它是不是那個因為不服從命令而被凍結的機器人？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"마, 맞습니다!","JPN":"ま、間違いありません！","ENG":"Y-yes, sir!","TWN":"是，是的！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"그런데 저게 갑자기 왜 여기에 나타나?!","JPN":"でも、あれがなぜここに現れたんだ！？","ENG":"Then, what's it doing here?","TWN":"它為什麼會突然出現？！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"통신이 들어왔습니다! 이 지역 정기순찰 계약을 맺고 있는 코핀 컴퍼니에서 구조 요청을 받고 왔다고 합니다.","JPN":"連絡が来ました！　救助要請を受けて、この地域の\\n定期巡察任務を担当するコフィンカンパニーから\\n駆け付けたそうです。","ENG":"I've got a message! The robot was sent by the Coffin Company that's under contract to patrol this area on a regular basis.","TWN":"收到通信！是在這裡執行定期巡查任務的科芬公司收到了求助請求後趕過來了。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"퓨처 앳 워에서 동결 처리 후 경매에 내놓은 것을 매입해서 재사용하고 있다는군요.","JPN":"フューチャーアットウォーから除外された後、競売に\\n出されていたのを買い付けて再利用しているそうです。","ENG":"Future-at-War froze and auctioned off the robot. Coffin is its new owner now.","TWN":"他們購買了被天啟兵器凍結的泰坦後重新啟用了。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"젠장! 사람 명령도 마음대로 무시하는 괴물이잖아?","JPN":"くそ！　人間の命令を好き勝手に無視するような、\\nとんでもない野郎じゃないか。","ENG":"Good Lord, that's a monster that ignores its orders.","TWN":"該死！那東西不是會無視人類命令的怪物嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"그런 걸 재사용하다니 제정신인가? 설마 우리를 공격하는 건 아니겠지?","JPN":"そんなのを再利用するなんて気は確かか？\\nまさか我々を攻撃するんじゃないだろうな？","ENG":"Why would anyone want to spend money on it? It's not going to attack us, is it?","TWN":"竟然重新啟用那種東西，是瘋了嗎？它應該不會攻擊我們吧？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"이런 이런, 젊은 친구들! 부끄럽게 왜 과거 이야기를 들추고 그러나?","JPN":"やれやれ、若い衆よ！　過去の話は恥ずかしいから\\nやめてくれたまえ。","ENG":"Well, well. Dear young fellows, let's not talk about my shameful past.","TWN":"喂喂，年輕朋友門！不要提往事嘛？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하지만 걱정은 필요 없네! 나의 빛나는 아틀라스 포신에 걸고 맹세하건대, 이 타이탄!","JPN":"もう心配ない！　吾輩の美しいアトラス砲身に\\nかけて誓うが、このタイタン！","ENG":"You have nothing to worry about. I swear upon my gleaming Atlas gun barrel.","TWN":"不用擔心！我對善良的阿特拉斯炮身發誓，我泰坦！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"비록 한낱 기계일 뿐이나 선량한 사람들을 다치게 한 적은 단연코 없다네!","JPN":"一機械にすぎないが、決して善良な人間を\\n傷つけたことはないぞ！","ENG":"I, Titan, may be a machine, but I've never hurt the innocent.","TWN":"雖然只是一個機器人，但從沒有傷害過善良的人類！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"서, 성격이...... 듣던 것과는 좀 다른 것 같은데요?","JPN":"せ、性格が……聞いていたのとはちょっと違いますね？","ENG":"I-its personality... It's different from what I heard.","TWN":"它的性格……好像和傳聞中的有些不一樣？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"그러게? 꼭 작년에 은퇴한 선임하사님 같은데......","JPN":"そ、そうだな……？　まるで去年引退された\\n曹長殿みたいじゃないか……","ENG":"I agree. It sounds like the First Sergeant who retired last year.","TWN":"是啊，跟去年剛退休的老下士很像……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"어쨌든 선택의 여지는 없군. 타이탄과 협력해서 해적들을 몰아붙인다!","JPN":"とにかく、選択の余地はない。タイタンと協力して\\n海賊どもを倒そう！","ENG":"Anyway, we've got no choice. Let's work together with Titan and drive away the pirates!","TWN":"不管怎樣，我們別無選擇，和泰坦一起對海盜發動反擊！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하! 고맙네! 맡겨두게나!","JPN":"ガハハ！　わかってくれてありがたい！　\\nまかせておけ！","ENG":"Hah hah! Thank you! You can count on me!","TWN":"哈哈！謝謝！交給我吧！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_04"}]`);export{e as default};